CREATE TABLE IF NOT EXISTS quiz_questions (
  id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  session_key INTEGER NOT NULL,
  sort_order INTEGER NOT NULL,
  question_text TEXT NOT NULL,
  options TEXT[] NOT NULL,
  correct_answer INTEGER NOT NULL,
  image_url TEXT DEFAULT '',
  explanation TEXT DEFAULT '',
  created_at TIMESTAMPTZ DEFAULT NOW()
);

TRUNCATE TABLE quiz_questions RESTART IDENTITY;

INSERT INTO quiz_questions (session_key, sort_order, question_text, options, correct_answer, image_url, explanation) VALUES
1, 0, "Apa definisi yang paling tepat mengenai WebGIS?", ARRAY["Aplikasi pengolah kata berbasis cloud yang mampu menampilkan tabel koordinat.", "Sistem Informasi Geografis yang diintegrasikan ke dalam arsitektur web untuk memvisualisasikan dan menganalisis data spasial secara online.", "Format file gambar khusus yang digunakan untuk menyimpan peta satelit resolusi tinggi.", "Database relasional lokal yang tidak terhubung ke jaringan internet."], 1, "", "WebGIS mengombinasikan kekuatan analisis GIS tradisional dengan kemudahan akses dan jangkauan distribusi platform web secara real-time.",
1, 1, "Perhatikan diagram arsitektur berikut. Bagian manakah yang bertugas untuk merender antarmuka peta dan menerima interaksi pengguna?", ARRAY["Database Server (seperti PostgreSQL)", "Backend API Server (seperti Node.js)", "Client/Frontend (Browser dengan library MapLibre)", "Cloud Storage (seperti AWS S3)"], 2, "https://upload.wikimedia.org/wikipedia/commons/thumb/5/5d/Client-server-model.svg/1200px-Client-server-model.svg.png", "Client/Frontend adalah sisi browser tempat pengguna berinteraksi langsung dengan peta spasial menggunakan JavaScript.",
1, 2, "Apa keunggulan utama arsitektur Dynamic WebGIS dibandingkan Static WebGIS?", ARRAY["Dynamic WebGIS tidak membutuhkan koneksi internet sama sekali.", "Dynamic WebGIS mampu merespon input pengguna, melakukan query database spasial, dan memperbarui layer secara langsung tanpa memuat ulang seluruh halaman.", "Dynamic WebGIS hanya menampilkan file gambar raster JPEG biasa yang aman.", "Dynamic WebGIS memiliki performa lebih lambat karena semua aset diunduh di awal."], 1, "", "Dynamic WebGIS memungkinkan interaksi dua arah, query spasial real-time, dan pembaruan visual instan di browser.",
1, 3, "Manakah tool bawaan browser yang sangat krusial untuk melakukan debugging error kode Javascript atau memantau network request di WebGIS?", ARRAY["Windows Explorer", "Developer Console (F12)", "Task Manager", "Registry Editor"], 1, "", "Developer Tools (F12) menyediakan tab Console untuk melacak log error JS dan tab Network untuk memantau request load ubin peta/API.",
1, 4, "Perhatikan gambar icon lock (🔒) di address bar browser berikut. Protokol standar apa yang sedang digunakan oleh client untuk berkomunikasi dengan server WebGIS secara aman?", ARRAY["FTP", "SMTP", "HTTP / HTTPS", "SSH"], 2, "https://upload.wikimedia.org/wikipedia/commons/thumb/1/11/HTTPS_icon.svg/800px-HTTPS_icon.svg.png", "Protokol HTTP/HTTPS digunakan untuk mengirimkan parameter query spasial dan menerima data spasial (seperti GeoJSON) dari server.",
1, 5, "Siapa target pengguna akhir (end-user) yang ideal untuk platform WebGIS interaktif?", ARRAY["Hanya developer web yang menulis baris kode.", "Hanya administrator database di server lokal.", "Siapa saja (masyarakat, pengambil keputusan, atau tim lapangan) yang membutuhkan insight spasial tanpa perlu menginstal software desktop GIS rumit.", "Komputer server otomatis yang memproses batch data."], 2, "", "WebGIS mendemokratisasi data spasial sehingga dapat diakses oleh publik luas cukup melalui browser di perangkat apa pun.",
1, 6, "Apa peran utama WebGIS dalam menunjang pengambilan keputusan bisnis di industri real estate?", ARRAY["Menghitung gaji karyawan di kantor pusat.", "Menganalisis lokasi potensial berdasarkan radius jangkauan pasar, densitas pesaing, dan demografi secara spasial.", "Membuat desain 3D bangunan secara arsitektural mendalam.", "Menyediakan jaringan internet berkecepatan tinggi di perumahan."], 1, "", "Analisis spasial lokasi (Location Intelligence) membantu pelaku bisnis real estate mengukur kecocokan lokasi komersial secara ilmiah.",
1, 7, "Logo library manakah yang ditampilkan pada gambar berikut, yang merupakan library JavaScript open-source populer untuk menampilkan peta interaktif di browser?", ARRAY["Django", "MapLibre GL JS", "PostgreSQL", "Pandas"], 1, "https://maplibre.org/img/maplibre-logo-big.svg", "MapLibre GL JS adalah library JavaScript client-side yang memanfaatkan WebGL untuk merender peta spasial berbasis vektor secara dinamis.",
1, 8, "Apa tantangan terbesar dalam memvisualisasikan jutaan data titik spasial di browser client?", ARRAY["Keterbatasan bandwidth kabel fiber optik internasional.", "Kapasitas memori dan rendering kartu grafis client (browser overload/crash jika merender terlalu banyak DOM element).", "Format data GeoJSON tidak didukung oleh browser modern.", "Ukuran layar monitor client terlalu sempit."], 1, "", "Merender ribuan/jutaan titik sebagai elemen HTML individual akan membebani DOM browser. Solusinya adalah teknik WebGL rendering atau clustering.",
1, 9, "Mengapa pemahaman dasar pemrograman web (HTML, CSS, JS) penting bagi seorang praktisi WebGIS?", ARRAY["Agar bisa menggantikan peran tim tim IT networking server utama.", "Untuk dapat merancang, memodifikasi interaksi peta, menyesuaikan UI dashboard, serta mengintegrasikan data spasial sesuai use-case industri nyata.", "Agar bisa merakit komputer server GIS fisik secara mandiri.", "Karena browser tidak bisa membaca data spasial jika ditulis dengan bahasa Python."], 1, "", "HTML/CSS/JS adalah fondasi utama pengembangan web. Tanpa ketiganya, peta WebGIS tidak bisa memiliki antarmuka interaktif yang fungsional.",
2, 0, "Apa perbedaan mendasar antara data spasial Vektor dan Raster?", ARRAY["Vektor menyimpan data dalam bentuk tabel teks, sedangkan Raster menyimpan data dalam bentuk suara spasial.", "Vektor merepresentasikan dunia nyata menggunakan titik, garis, dan poligon geometris; sedangkan Raster menggunakan kisi-kisi piksel (grid) bernilai.", "Raster selalu memiliki akurasi koordinat yang jauh lebih tinggi daripada Vektor di setiap skala.", "Vektor hanya bisa digunakan untuk menyimpan citra satelit berwarna."], 1, "", "Data vektor mendefinisikan objek spasial dengan titik koordinat diskret (x, y), sedangkan raster terdiri dari matriks sel piksel berkelanjutan.",
2, 1, "Sistem koordinat manakah yang merepresentasikan posisi di bumi dalam satuan derajat busur/geografis (Bujur/Lintang)?", ARRAY["UTM Zone 49N", "WGS 84 (EPSG:4326)", "Web Mercator (EPSG:3857)", "State Plane Coordinate System"], 1, "", "EPSG:4326 (WGS 84) adalah sistem koordinat geografis (GCS) unprojected berwujud bola ellipsoid yang diukur dalam satuan derajat decimal.",
2, 2, "Sistem koordinat terproyeksi manakah yang paling dominan digunakan dalam rendering peta web dinamis (seperti Google Maps, Mapbox, dan MapLibre)?", ARRAY["WGS 84 Geografis (EPSG:4326)", "Web Mercator (EPSG:3857)", "UTM Zone 48S", "DMS (Degrees Minutes Seconds)"], 1, "", "EPSG:3857 (Web Mercator) memproyeksikan bumi menjadi bidang datar persegi dalam satuan meter untuk mempermudah perhitungan ubin peta (tiles) secara cepat.",
2, 3, "Format file teks spasial berbasis JSON yang menjadi standar utama pertukaran data vektor di WebGIS adalah...", ARRAY["Shapefile (SHP)", "GeoJSON", "Keyhole Markup Language (KML)", "GPX"], 1, "", "GeoJSON sangat disukai developer web karena formatnya yang human-readable, berbasis standar JSON, dan langsung dapat di-parse sebagai objek JavaScript asli.",
2, 4, "Manakah struktur objek GeoJSON yang valid di bawah ini untuk tipe geometri Titik (Point)?", ARRAY["{ \"type\": \"Point\", \"coords\": [106.8, -6.2] }", "{ \"type\": \"Point\", \"coordinates\": [106.8, -6.2] }", "{ \"geometry\": \"Point\", \"coordinates\": [-6.2, 106.8] }", "{ \"type\": \"Feature\", \"geometry\": \"point\", \"coords\": [-6.2, 106.8] }"], 1, "", "Sesuai spesifikasi RFC 7946, objek geometri GeoJSON berjenis Point wajib memiliki properti 'type' bernilai 'Point' (case-sensitive) dan 'coordinates' berupa array `[longitude, latitude]`.",
2, 5, "Dalam standar koordinat GeoJSON `[X, Y]`, nilai manakah yang diletakkan pada posisi indeks ke-0?", ARRAY["Latitude (Lintang)", "Longitude (Bujur)", "Ketinggian (Elevation)", "Kode EPSG"], 1, "", "GeoJSON menggunakan urutan koordinat `[Bujur (X/Eastings), Lintang (Y/Northings)]`, berbeda dari penyebutan lisan umum yang mendahulukan Latitude.",
2, 6, "Apa kelemahan utama format ESRI Shapefile jika langsung digunakan dalam aplikasi web modern?", ARRAY["Shapefile tidak dapat menyimpan data atribut tabel.", "Shapefile adalah format biner multi-file (membutuhkan file .shp, .shx, .dbf) yang tidak efisien dimuat langsung secara asinkronus oleh browser.", "Shapefile hanya bisa dibuka di software berlisensi mahal.", "Shapefile tidak mendukung koordinat WGS 84."], 1, "", "Shapefile mewajibkan pengiriman beberapa file terpisah sekaligus, berukuran besar, berformat biner, serta membatasi nama kolom tabel maksimal 10 karakter.",
2, 7, "Apa tujuan utama dilakukannya 'Proyeksi Peta'?", ARRAY["Menggandakan ukuran data spasial agar lebih akurat.", "Mengubah koordinat 3D dari permukaan bumi bulat oval menjadi koordinat 2D pada bidang datar agar dapat divisualisasikan pada layar.", "Membuat peta menjadi tiga dimensi menggunakan kacamata khusus.", "Mendeteksi keberadaan satelit cuaca secara realtime."], 1, "", "Proyeksi peta memetakan permukaan melengkung bumi (ellipsoid) ke bidang datar datar, yang pasti menghasilkan distorsi pada luas, bentuk, jarak, atau arah.",
2, 8, "Apa yang dimaksud dengan 'Datum' dalam kartografi spasial?", ARRAY["Nama file data spasial yang tersimpan di server cloud.", "Model matematis bumi yang digunakan sebagai referensi untuk menghitung koordinat geografis objek di permukaan bumi.", "Alat pengukur kemiringan tanah otomatis.", "Batas wilayah administratif suatu negara."], 1, "", "Datum mendefinisikan posisi pusat dan orientasi elipsoid referensi terhadap pusat bumi. Datum paling populer adalah WGS 84.",
2, 9, "Manakah di bawah ini yang merupakan contoh dari data spasial Raster?", ARRAY["Data rute jalan berbentuk GeoJSON LineString.", "Batas wilayah kabupaten berbentuk poligon GeoJSON.", "Citra Satelit Sentinel atau Model Elevasi Digital (DEM) dalam format GeoTIFF.", "Titik-titik koordinat minimarket dalam format CSV."], 2, "", "GeoTIFF menyimpan grid piksel berskala abu-abu atau multi-band warna yang melambangkan pantulan spektral satelit atau ketinggian permukaan tanah.",
3, 0, "Apa peran utama GEO MAPID dalam arsitektur WebGIS bootcamp kita?", ARRAY["Sebagai code editor tempat menulis sintaks Javascript.", "Sebagai platform cloud database spasial terintegrasi untuk menyimpan, mengedit (digitasi), dan mempublikasikan data spasial melalui REST API.", "Sebagai hosting server untuk mendeploy website frontend HTML.", "Sebagai library rendering grafis pengganti WebGL."], 1, "", "GEO MAPID berfungsi sebagai Database-as-a-Service (DBaaS) yang menyederhanakan penyimpanan data spasial dan menyediakan API Endpoint siap pakai untuk frontend.",
3, 1, "Bagaimana cara memasukkan data spasial lokal (seperti Shapefile atau GeoJSON) ke dalam GEO MAPID?", ARRAY["Dengan menulis ulang koordinat titik demi titik di console Javascript.", "Menggunakan fitur Import Layer pada dashboard GEO MAPID untuk mengunggah file spasial (misal .zip shapefile atau .json).", "Mengirimkan file fisik CD/Flashdisk ke kantor MAPID.", "Menginstal database PostgreSQL lokal lalu menghubungkannya via kabel LAN."], 1, "", "Dashboard GEO MAPID menyediakan alat import drag-and-drop otomatis yang mengoversi format spasial desktop ke format database awan MAPID.",
3, 2, "Fitur apa di GEO MAPID yang memungkinkan kita menggambar objek spasial langsung di atas peta tanpa aplikasi desktop GIS?", ARRAY["REST API generator", "Digitize / Drawing Tools", "Python Compiler", "BBOX Terminal"], 1, "", "Alat digitasi online GEO MAPID memudahkan user menggambar geometri titik (Point), garis (Line), maupun area (Polygon) langsung menggunakan browser.",
3, 3, "Parameter penting apa yang wajib kita sertakan dalam header HTTP Request agar frontend diizinkan mengambil data spasial privat dari API GEO MAPID?", ARRAY["Database Password", "MAPID API Key (Authorization / Token)", "Sesi login admin", "Email pendaftaran bootcamp"], 1, "", "API Key bertindak sebagai token pengenal unik untuk memvalidasi hak akses client terhadap data spasial yang tersimpan di GEO MAPID secara aman.",
3, 4, "Data format apa yang akan dikembalikan (response) oleh API GEO MAPID saat kita meminta data spasial vektor untuk ditampilkan di MapLibre?", ARRAY["XML format", "GeoJSON / JSON", "Biner Shapefile mentah", "PDF Peta Cetak"], 1, "", "API MAPID didesain untuk platform web modern, sehingga mengembalikan response berformat standard GeoJSON yang sangat ramah terhadap JavaScript.",
3, 5, "Mengapa menyimpan data spasial di cloud (seperti GEO MAPID) lebih diunggulkan daripada menyimpan file GeoJSON lokal di dalam folder proyek web?", ARRAY["Karena file lokal tidak bisa dibaca oleh compiler JavaScript frontend.", "Karena dengan database cloud, data spasial dapat diperbarui (CRUD), difilter, dan diakses oleh banyak pengguna secara dinamis dan real-time tanpa perlu mengubah kode sumber website.", "Penyimpanan cloud dijamin 100% gratis tanpa batasan kuota selamanya.", "Data lokal di folder proyek sangat mudah terserang virus biner."], 1, "", "Decoupling data dari source-code meningkatkan efisiensi arsitektur. Anda bisa mengubah data peta di dashboard GEO MAPID dan website otomatis ter-update.",
3, 6, "Menu apa di GEO MAPID yang digunakan untuk mengelola skema tabel data, menambah kolom atribut baru, atau mengedit entri data spasial?", ARRAY["API Console", "Table / Attribute Editor", "Styling Wizard", "GeoServer Manager"], 1, "", "Table Editor di GEO MAPID memungkinkan pengguna mengelola data non-spasial (atribut teks/angka) yang terikat langsung pada setiap fitur geometri.",
3, 7, "Apa kegunaan utama dari fitur 'Publish Layer' di GEO MAPID?", ARRAY["Mengirim email notifikasi ke mentor bootcamp.", "Mengaktifkan API endpoint publik untuk layer spasial tertentu sehingga dapat diakses oleh aplikasi web eksternal.", "Mengunduh seluruh isi layer ke komputer lokal.", "Mendatangkan ribuan pengunjung ke website secara otomatis."], 1, "", "Publishing layer mengubah status layer spasial menjadi API-ready, memberikan akses GET request yang aman bagi aplikasi client.",
3, 8, "Apakah kita bisa menggabungkan beberapa jenis geometri (misal titik dan poligon) di dalam satu layer yang sama di GEO MAPID sesuai kaidah GIS yang baik?", ARRAY["Ya, GEO MAPID membolehkan pencampuran semua jenis geometri tanpa batasan.", "Tidak, standar GIS yang baik mewajibkan satu layer berfokus pada satu jenis geometri homogen (khusus titik saja, khusus garis saja, atau khusus poligon saja) agar konsisten dalam styling dan analisis.", "Bisa, asalkan data diimpor menggunakan file berekstensi .txt.", "Bisa, namun visualisasinya hanya bisa berbentuk hitam-putih."], 1, "", "Memisahkan tipe geometri ke dalam layer berbeda adalah best practice kartografi spasial demi kelancaran proses styling, query, dan analisis spasial.",
3, 9, "Use-case industri nyata manakah yang paling pas memanfaatkan integrasi API GEO MAPID?", ARRAY["Membuat aplikasi pemutar musik offline.", "Sistem monitoring kurir pengantar logistik secara real-time yang memperbarui titik koordinat armada langsung ke server spasial pusat.", "Membuat game arcade sederhana berformat 2D.", "Mengompres ukuran gambar foto profil website."], 1, "", "GEO MAPID mempermudah pengiriman data spasial dinamis dari lapangan langsung masuk database awan dan tercermin instan pada dashboard peta WebGIS pemantau.",
4, 0, "Apa fungsi utama dari bahasa pemrograman HTML dalam pengembangan website?", ARRAY["Mengatur logika perhitungan data dan koneksi database.", "Mendefinisikan struktur dasar dan elemen konten dari halaman web.", "Menyediakan animasi interaktif dan efek suara spasial.", "Mengunggah file proyek web ke server hosting awan."], 1, "", "HTML (HyperText Markup Language) bertindak sebagai kerangka tulang belulang website yang merangkum teks, gambar, tombol, dan tautan.",
4, 1, "Tag HTML manakah yang paling tepat digunakan untuk membungkus peta WebGIS yang akan dirender lewat JavaScript?", ARRAY["<map>", "<div>", "<img>", "<canvas>"], 1, "", "Elemen `<div>` (division) bertindak sebagai kontainer kosong generik yang nantinya akan diincar oleh instansiasi MapLibre via ID unik kontainer tersebut.",
4, 2, "Bagaimana cara menghubungkan file styling CSS eksternal ke dalam file dokumen HTML?", ARRAY["<script src=\"style.css\"></script>", "<link rel=\"stylesheet\" href=\"style.css\" />", "<style src=\"style.css\"></style>", "<a href=\"style.css\">Import CSS</a>"], 1, "", "Tag `<link>` diletakkan di dalam bagian `<head>` HTML untuk memuat file stylesheet CSS luar guna menata seluruh penampilan website.",
4, 3, "Apa perbedaan mendasar dalam penggunaan atribut ID dan Class pada elemen HTML?", ARRAY["ID ditujukan untuk menata elemen teks, sedangkan Class ditujukan untuk gambar.", "ID bersifat unik dan hanya boleh digunakan oleh satu elemen spesifik di halaman web; sedangkan Class bersifat reusable dan dapat dibagikan ke banyak elemen sekaligus.", "ID ditulis menggunakan huruf kapital saja, sedangkan Class harus menggunakan huruf kecil.", "ID hanya dapat dibaca oleh CSS, sedangkan Class hanya dapat dibaca oleh JavaScript."], 1, "", "ID adalah penanda unik mutlak (biasanya dipakai targeting JS DOM atau style khusus), sementara Class digunakan untuk mengelompokkan elemen ber-gaya serupa.",
4, 4, "Atribut HTML manakah yang wajib disertakan pada elemen `<a>` untuk menentukan URL halaman tujuan saat tautan tersebut diklik?", ARRAY["src", "link", "href", "target"], 2, "", "Atribut `href` (Hypertext Reference) menyimpan alamat link tujuan, baik alamat relatif dalam proyek maupun alamat eksternal internet penuh.",
4, 5, "Manakah penulisan komentar yang benar di dalam file dokumen HTML?", ARRAY["// Ini komentar HTML", "/* Ini komentar HTML */", "<!-- Ini komentar HTML -->", "# Ini komentar HTML"], 2, "", "Komentar HTML diawali dengan `<!--` dan diakhiri dengan `-->`. Kode di dalamnya tidak akan dirender oleh browser.",
4, 6, "Apa kepanjangan dari singkatan bahasa desain CSS?", ARRAY["Computer Style Sheets", "Cascading Style Sheets", "Creative Style Systems", "Complex Styling Standards"], 1, "", "CSS (Cascading Style Sheets) mendeskripsikan bagaimana elemen HTML ditampilkan di layar, kertas, atau media visual lainnya.",
4, 7, "Bagaimana cara memilih (select) sebuah elemen HTML dengan ID bernama 'map-container' di dalam kode CSS?", ARRAY[".map-container { }", "#map-container { }", "map-container { }", "@map-container { }"], 1, "", "Dalam selektor CSS, karakter pagar `#` melambangkan pemilihan elemen berdasarkan atribut ID uniknya.",
4, 8, "Properti CSS manakah yang digunakan untuk mengubah warna latar belakang sebuah kontainer panel dashboard?", ARRAY["color", "font-color", "background-color", "border-color"], 2, "", "Properti `background-color` digunakan untuk mengisi warna latar, sedangkan `color` khusus digunakan untuk mengatur warna teks.",
4, 9, "Model penulisan warna CSS manakah yang mendukung penyesuaian transparansi (opacity) agar peta di belakang panel tetap samar-samar terlihat?", ARRAY["HEX (#FF0000)", "RGB (255, 0, 0)", "RGBA (255, 0, 0, 0.5)", "Warna bernama (red)"], 2, "", "Huruf 'A' pada RGBA melambangkan Alpha (saluran transparansi) dengan rentang nilai dari 0.0 (transparan penuh) hingga 1.0 (pekat/solid).",
5, 0, "Dalam CSS Box Model, apa perbedaan antara Margin dan Padding?", ARRAY["Margin adalah batas ketebalan border garis, sedangkan Padding adalah tinggi keseluruhan elemen.", "Margin mengatur jarak kosong di luar batas border elemen; sedangkan Padding mengatur jarak kosong di dalam elemen (antara konten dan border).", "Margin hanya berlaku untuk elemen teks, sedangkan Padding hanya berlaku untuk kontainer div.", "Margin berada di dalam elemen, sedangkan Padding berada di luar batas terluar elemen."], 1, "", "Margin menciptakan ruang di sekeliling luar kotak elemen untuk menjauhkan elemen tetangga, sedangkan padding memberi ruang pernapasan internal konten.",
5, 1, "Sistem tata letak (layout) CSS manakah yang didesain khusus untuk mengatur susunan elemen satu dimensi (baik horizontal saja atau vertikal saja)?", ARRAY["CSS Grid", "Flexbox (Flexible Box)", "Absolute Positioning", "Table Layout"], 1, "", "Flexbox mempermudah penyelarasan elemen-elemen anak di sepanjang sumbu utama (main-axis) secara fleksibel, sangat pas untuk navbar atau baris kartu.",
5, 2, "Bagaimana cara menyusun tata letak dua dimensi yang kompleks (baris dan kolom sekaligus, seperti grid dashboard modular) secara bersih?", ARRAY["Flexbox", "CSS Grid Layout", "Floats", "Inline-block elements"], 1, "", "CSS Grid dirancang khusus untuk layout dua dimensi (baris & kolom), memberikan kendali penuh terhadap penempatan posisi grid-item.",
5, 3, "Properti Flexbox manakah yang digunakan untuk mengatur agar elemen-elemen anak bergeser ke sumbu utama (misal rata tengah horizontal)?", ARRAY["align-items", "justify-content", "flex-direction", "flex-wrap"], 1, "", "Properti `justify-content` mengatur distribusi elemen-elemen anak di sepanjang sumbu utama (biasanya horizontal), dengan nilai seperti center, space-between.",
5, 4, "Properti CSS manakah yang digunakan untuk membulatkan sudut-sudut tajam sebuah kartu panel atau tombol peta agar terkesan modern?", ARRAY["border-style", "border-width", "border-radius", "box-shadow"], 2, "", "Properti `border-radius` menerima satuan piksel (px) atau persen (%) untuk melengkungkan sudut elemen secara halus.",
5, 5, "Teknik CSS apa yang digunakan agar gaya tampilan website dapat beradaptasi secara otomatis ketika dibuka di layar handphone yang sempit?", ARRAY["CSS Animations", "Media Queries (@media)", "CSS Variables", "Absolute margins"], 1, "", "Media Queries memungkinkan kita menulis blok CSS khusus yang hanya aktif ketika lebar viewport layar menyentuh ukuran batas tertentu (breakpoint).",
5, 6, "Properti layout flexbox manakah yang wajib disetel agar elemen-elemen anak otomatis melompat ke baris baru ketika ruang kontainer sudah habis?", ARRAY["flex-direction: column", "flex-wrap: wrap", "align-content: stretch", "display: block"], 1, "", "Secara default flex-items akan dipaksa menyusut dalam satu baris. Menggunakan `flex-wrap: wrap` mengizinkan elemen turun ke bawah secara natural.",
5, 7, "Dalam mendesain antarmuka modern, efek visual apa yang memberikan bayangan lembut di bawah kartu dashboard agar terlihat melayang di atas peta?", ARRAY["text-shadow", "box-shadow", "background-shadow", "opacity"], 1, "", "Properti `box-shadow` memberikan efek kedalaman (depth) 3D palsu pada elemen dengan menentukan offset bayangan, keburaman (blur), dan warna.",
5, 8, "Apa arti dari nilai CSS properti `position: absolute`?", ARRAY["Elemen akan mengalir secara normal mengikuti alur dokumen.", "Elemen diposisikan relatif terhadap viewport layar browser dan tidak bergeser saat di-scroll.", "Elemen ditarik keluar dari alur dokumen normal dan diposisikan secara presisi relatif terhadap leluhur (parent) terdekatnya yang berstatus non-static.", "Elemen otomatis bersembunyi dan tidak dapat diklik."], 2, "", "Menggunakan `position: absolute` memungkinkan kita meletakkan kontrol HUD koordinat atau tombol zoom tepat di atas peta secara melayang.",
5, 9, "Bagaimana cara membuat efek transisi perubahan warna tombol yang halus saat disorot kursor (hover)?", ARRAY["Menggunakan properti transition CSS (misal `transition: background 0.3s ease`)", "Menulis fungsi Javascript interaktif yang mengganti stylesheet.", "Mengimpor animasi video GIF berulang.", "Mengubah format gambar tombol menjadi SVG terkompresi."], 0, "", "Properti `transition` menginstruksikan browser untuk memperhalus perubahan properti CSS yang dipicu oleh selector seperti `:hover`.",
6, 0, "Manakah cara deklarasi variabel di JavaScript modern (ES6) yang membatasi cakupan variabel hanya di dalam blok kode (block scope) tempat ia dibuat?", ARRAY["var", "let & const", "global", "def"], 1, "", "`let` dan `const` memiliki cakupan lokal blok (block-scoped `{}`), mengeliminasi risiko polusi variabel global atau hoisting aneh yang sering terjadi pada `var`.",
6, 1, "Apa perbedaan krusial antara pendeklarasian variabel menggunakan `let` dan `const`?", ARRAY["Const hanya dapat menyimpan data bertipe angka, sedangkan Let bisa teks.", "Nilai variabel Let dapat diubah/ditulis ulang kapan saja (mutable); sedangkan variabel Const bertindak sebagai konstanta yang nilainya tidak dapat di-reassign (immutable) setelah diinisialisasi.", "Let membutuhkan memori penyimpanan komputer lebih besar dari Const.", "Const otomatis diekspor ke database server sedangkan Let tidak."], 1, "", "Gunakan `const` untuk referensi yang tidak akan di-reassign demi menjaga konsistensi kode dan mencegah bug yang tidak disengaja.",
6, 2, "Manakah tipe data JavaScript di bawah ini yang digunakan untuk menyimpan kumpulan data terurut yang diakses menggunakan indeks angka?", ARRAY["Object", "Array", "String", "Boolean"], 1, "", "Array dideklarasikan menggunakan kurung siku `[...]` dan berisi daftar elemen terurut yang diindeks mulai dari angka 0.",
6, 3, "Tipe data manakah yang paling ideal untuk merepresentasikan fitur spasial tunggal yang memiliki atribut kompleks (kunci dan nilai/key-value pairs)?", ARRAY["Array", "Object", "Function", "Null"], 1, "", "Objek JavaScript ditulis menggunakan kurung kurawal `{}` dan menyimpan pasangan key-value, sangat pas untuk mewakili bagian `properties` di GeoJSON.",
6, 4, "Method Array manakah yang digunakan untuk memproses dan menyaring elemen array agar menyisakan data yang lolos kriteria tertentu saja (misal mencari peserta dengan nilai > 80)?", ARRAY["array.map()", "array.forEach()", "array.filter()", "array.push()"], 2, "", "`filter()` mengembalikan array baru berisi semua elemen yang lolos uji kondisi fungsi callback penyaring.",
6, 5, "Bagaimana cara menulis conditional statement (percabangan logika) di JavaScript?", ARRAY["if (kondisi) { ... }", "if kondisi: ...", "select kondisi case ...", "either (kondisi) or { ... }"], 0, "", "Blok `if` mengevaluasi kondisi di dalam tanda kurung biasa `()`, jika bernilai true maka blok kode di dalam kurung kurawal `{}` akan dieksekusi.",
6, 6, "Manakah penulisan fungsi Arrow Function (sintaks modern ES6) yang valid di JavaScript?", ARRAY["const myFunc = function() => { }", "const myFunc = () => { }", "def myFunc() => { }", "arrow myFunc() { }"], 1, "", "Arrow Function `() => { }` menyediakan sintaks penulisan fungsi yang lebih ringkas dan mempertahankan lexical binding terhadap nilai `this`.",
6, 7, "Apa kegunaan dari method `console.log()`?", ARRAY["Menampilkan kotak dialog peringatan pop-up di layar pengguna.", "Mencetak informasi atau melacak isi nilai variabel ke tab Console Developer Tools browser untuk tujuan inspeksi/debugging.", "Mengirimkan data langsung ke server database cloud MAPID.", "Memaksa browser client berhenti memproses skrip JavaScript."], 1, "", "`console.log()` adalah sahabat terdekat developer untuk mengintip isi data spasial, melacak alur eksekusi fungsi, atau menangkap log error.",
6, 8, "Apa output dari evaluasi perbandingan nilai dan tipe data berikut: `100 === '100'`?", ARRAY["true", "false", "undefined", "NaN"], 1, "", "Operator `===` (strict equality) memeriksa kesamaan nilai SEKALIGUS tipe datanya. Karena tipe data kiri adalah Number dan kanan adalah String, hasilnya adalah false.",
6, 9, "Method Array manakah yang digunakan untuk menyisipkan satu elemen baru ke posisi paling akhir dari sebuah Array?", ARRAY["array.pop()", "array.shift()", "array.push()", "array.join()"], 2, "", "`push()` memodifikasi array asli dengan menambahkan satu atau lebih elemen baru ke ujung ekor array dan mengembalikan panjang array baru.",
7, 0, "Apa kepanjangan dari istilah DOM dalam JavaScript browser?", ARRAY["Database Object Model", "Document Object Model", "Data Organization Method", "Dynamic Object Management"], 1, "", "DOM (Document Object Model) adalah API antarmuka pemrograman untuk dokumen HTML. DOM merepresentasikan halaman web sebagai pohon struktur objek (node tree).",
7, 1, "Fungsi bawaan JavaScript manakah yang paling modern dan serbaguna untuk menargetkan/memilih satu elemen HTML berdasarkan selektor CSS (seperti class atau ID)?", ARRAY["document.getElementByTagName()", "document.querySelector()", "document.getElementById()", "document.findCSS()"], 1, "", "`querySelector()` menerima string selektor CSS standar apa pun dan mengembalikan elemen DOM pertama yang cocok.",
7, 2, "Method DOM manakah yang digunakan untuk mendaftarkan aksi interaksi (seperti mendeteksi klik tombol) agar memicu baris kode JavaScript tertentu?", ARRAY["element.triggerEvent()", "element.addEventListener()", "element.onClick()", "element.bindAction()"], 1, "", "`addEventListener('nama_event', callback)` mendaftarkan pendengar event pada target DOM sehingga callback terpanggil setiap kali event tersebut terpicu.",
7, 3, "Bagaimana cara mengubah isi teks di dalam sebuah elemen HTML secara dinamis menggunakan DOM manipulation?", ARRAY["element.textContent = 'Teks Baru';", "element.writeText('Teks Baru');", "element.src = 'Teks Baru';", "element.value = 'Teks Baru';"], 0, "", "Mengisi properti `textContent` atau `innerText` akan menimpa seluruh teks konten di dalam tag elemen target secara aman.",
7, 4, "Bagaimana cara mengambil nilai string input teks (misalnya tautan pengumpulan tugas) dari sebuah elemen input HTML?", ARRAY["inputElement.textContent", "inputElement.value", "inputElement.getAttribute('text')", "inputElement.innerHTML"], 1, "", "Elemen form input (seperti `<input>` atau `<textarea>`) menyimpan data ketikan pengguna di dalam properti `.value`.",
7, 5, "Method JavaScript modern manakah yang digunakan untuk melakukan pemanggilan data dari API eksternal (seperti API GEO MAPID) secara asinkron (Asynchronous)?", ARRAY["XMLHTTPRequest", "fetch()", "axios.get()", "ajax()"], 1, "", "API `fetch()` adalah standar web modern berbasis Promise yang mempermudah request HTTP asinkron langsung dari browser tanpa library luar.",
7, 6, "Apa fungsi utama dari blok penanganan error `try { ... } catch (error) { ... }` di JavaScript?", ARRAY["Mencegah browser mendeploy aplikasi jika ada bug.", "Mengisolasi kode yang berisiko memicu error (misal parsing data JSON rusak) agar program tidak crash total, dan membelokkan alur penanganan error secara elegan.", "Menghapus seluruh variabel global untuk menghemat memori.", "Memaksa fungsi asinkron berjalan secara sinkron."], 1, "", "Mengurung operasi sensitif (seperti parsing JSON atau request network) dengan `try-catch` menjamin aplikasi tetap berjalan mulus meskipun terjadi kendala tak terduga.",
7, 7, "Sintaksis modern manakah yang digunakan untuk mempermudah penulisan operasi asinkron agar terlihat seperti baris kode sinkron yang rapi?", ARRAY["then / catch", "async / await", "promise / resolve", "try / catch"], 1, "", "Kata kunci `async` menandai sebuah fungsi asinkron dan `await` menunda eksekusi baris berikutnya sampai Promise di depannya selesai diselesaikan.",
7, 8, "Method DOM manakah yang digunakan untuk memodifikasi daftar class gaya pada elemen (misal menambahkan class aktif atau menghapus class tersembunyi)?", ARRAY["element.className = 'active'", "element.classList.add() / element.classList.remove()", "element.setStyle('class', 'active')", "element.attributes.add('class')"], 1, "", "Objek properti `classList` menyediakan helper manipulasi class yang sangat lengkap seperti `.add()`, `.remove()`, `.toggle()`, dan `.contains()`.",
7, 9, "Fungsi bawaan JavaScript manakah yang digunakan untuk mengoversi data String berformat JSON menjadi objek JavaScript utuh agar bisa diakses propertinya?", ARRAY["JSON.stringify()", "JSON.parse()", "JSON.toObject()", "String.parseJSON()"], 1, "", "`JSON.parse(string)` membaca teks mentah beraliran JSON dan membangun struktur objek/array JS yang cocok, sedangkan `JSON.stringify(object)` melakukan kebalikannya.",
8, 0, "Apa keunggulan utama peta berbasis Vector Tiles (seperti MapLibre GL JS) dibandingkan Raster Tiles tradisional?", ARRAY["Vector tiles memiliki ukuran file gambar yang jauh lebih besar.", "Vector tiles mengirimkan data geometri asli ke browser, memungkinkan proses styling, rotasi peta 3D yang sangat mulus, dan interaktivitas tingkat tinggi langsung di sisi client tanpa blur saat di-zoom.", "Vector tiles tidak membutuhkan kartu grafis (GPU) untuk merender visual.", "Vector tiles hanya dapat menampilkan peta hitam-putih."], 1, "", "Vector tiles mengirim koordinat matematika geometris mentah. Browser client memanfaatkan WebGL kartu grafis untuk merender visual peta secara dinamis di setiap tingkat perbesaran.",
8, 1, "Objek global apa di dalam pustaka MapLibre GL JS yang diinstansiasi untuk membangun sebuah peta baru di halaman web?", ARRAY["maplibregl.CreateMap()", "new maplibregl.Map()", "maplibregl.Init()", "new maplibregl.WebMap()"], 1, "", "Konstruktor `new maplibregl.Map(options)` dipanggil dengan membawa konfigurasi objek wajib untuk melahirkan elemen kanvas peta fungsional.",
8, 2, "Di dalam objek konfigurasi `new maplibregl.Map()`, properti manakah yang digunakan untuk mengincar ID elemen HTML kontainer pembungkus peta?", ARRAY["id", "target", "container", "element"], 2, "", "Properti `container` menerima string ID elemen HTML tempat peta akan diletakkan (misal `container: 'map'`).",
8, 3, "Secara default, format urutan array koordinat center manakah yang digunakan oleh MapLibre GL JS?", ARRAY["[Latitude, Longitude]", "[Longitude, Latitude]", "[X, Y, Z]", "[Easting, Northing]"], 1, "", "Seperti standar Web Mercator, MapLibre GL JS mewajibkan penulisan koordinat pusat peta dalam urutan `[Bujur/Longitude, Lintang/Latitude]`.",
8, 4, "Bagaimana cara menyertakan library CSS dan JavaScript MapLibre GL JS ke dalam proyek web kita?", ARRAY["Tidak perlu diimpor, browser otomatis memiliki library MapLibre bawaan.", "Melalui CDN link CSS dan tag script JS MapLibre di file HTML, atau menginstalnya via NPM (`npm i maplibre-gl`) dalam pengembangan modern.", "Dengan mengunduh citra peta dalam format JPG lalu diletakkan di folder proyek.", "Dengan menghubungkannya langsung ke database SQL."], 1, "", "Anda dapat memuat aset CDN MapLibre lewat tag `<link>` dan `<script>` pada HTML, atau melalui npm/yarn untuk setup arsitektur berbasis module bundler.",
8, 5, "Apa fungsi dari properti `style` pada inisialisasi MapLibre GL JS?", ARRAY["Mengatur lebar dan tinggi elemen kanvas peta di layar.", "Menentukan skema desain visual peta, sumber ubin data vektor/raster, dan definisi layer dasar (basemap) berformat JSON.", "Mengubah warna teks tombol kontrol zoom.", "Menyimpan kredensial API key."], 1, "", "Properti `style` menunjuk ke URL file JSON spesifikasi Mapbox Style yang mendeskripsikan font peta, susunan basemap, ubin jalan, bangunan, dll.",
8, 6, "Dalam MapLibre, tingkat kedekatan tampilan peta dengan permukaan tanah diatur oleh properti...", ARRAY["scale", "zoom", "pitch", "bearing"], 1, "", "Properti `zoom` menerima angka desimal (biasanya antara 0 hingga 22) untuk mengatur level kedekatan perbesaran kamera peta.",
8, 7, "Properti inisialisasi MapLibre manakah yang digunakan untuk memiringkan sudut pandang kamera (3D Perspective) agar efek 3D gedung terlihat menonjol?", ARRAY["bearing", "pitch", "rotation", "skew"], 1, "", "Properti `pitch` mengatur kemiringan sudut kamera dalam satuan derajat (0 melambangkan pandangan 2D tegak lurus dari atas ke bawah, 60-85 melambangkan miring perspektif).",
8, 8, "Properti inisialisasi MapLibre manakah yang digunakan untuk memutar arah hadap peta (rotasi arah mata angin kamera)?", ARRAY["bearing", "pitch", "direction", "orientation"], 0, "", "Properti `bearing` mengatur rotasi peta dalam derajat searah jarum jam dari arah Utara (0 melambangkan Utara tegak lurus ke atas).",
8, 9, "Mengapa disarankan mematikan interaktivitas rotasi peta pada beberapa jenis dashboard analisis bisnis WebGIS?", ARRAY["Karena browser akan otomatis crash jika peta diputar.", "Agar peta dasar selalu terkunci stabil menghadap ke arah Utara, memudahkan pembacaan distribusi spasial bagi pengguna awam tanpa kebingungan arah kompas.", "Karena MapLibre tidak mendukung fitur rotasi sama sekali.", "Agar konsumsi kuota API Key menjadi lebih hemat."], 1, "", "Mengunci opsi rotasi (`dragRotate: false`, `touchZoomRotate: false`) menghindarkan user memutar peta secara tidak sengaja yang bisa mendistorsi persepsi spasial.",
9, 0, "Dalam MapLibre GL JS, apa perbedaan konseptual antara 'Source' dan 'Layer'?", ARRAY["Source adalah nama database eksternal, sedangkan Layer adalah file styling CSS.", "Source mendefinisikan data mentah spasial (koordinat geometri dan atribut) yang akan ditampilkan; sedangkan Layer mendefinisikan bagaimana data dari Source tersebut digambar secara visual (misal sebagai titik merah, garis tebal, atau poligon transparan).", "Source bertugas untuk menangkap interaksi klik user, sedangkan Layer bertugas memutar peta.", "Source hanya mendukung format gambar satelit, sedangkan Layer hanya mendukung GeoJSON."], 1, "", "Source adalah pemasok data (geometri/atribut) di balik layar, sedangkan Layer adalah representasi visual di atas kanvas yang terikat pada salah satu Source.",
9, 1, "Method JavaScript manakah yang digunakan untuk mendaftarkan sumber data spasial baru (seperti objek GeoJSON) ke dalam instansiasi peta MapLibre?", ARRAY["map.addLayer()", "map.addSource()", "map.setFeature()", "map.pushData()"], 1, "", "`map.addSource(id, options)` mendaftarkan sumber data spasial baru ke dalam map state dengan memberikan ID referensi unik.",
9, 2, "Method JavaScript manakah yang digunakan untuk menggambar secara visual data yang telah didaftarkan di Source ke atas peta?", ARRAY["map.draw()", "map.addLayer()", "map.addSource()", "map.injectLayer()"], 1, "", "`map.addLayer(options)` digunakan untuk merender data spasial dari Source ke peta dengan menentukan tipe layer dan gaya visualisasinya.",
9, 3, "Di dalam pemanggilan method `map.addSource()`, opsi properti manakah yang digunakan untuk menentukan format data yang dimasukkan (misalnya 'geojson')?", ARRAY["format", "type", "dataType", "sourceType"], 1, "", "Properti `type` menetapkan jenis sumber data, seperti 'geojson', 'vector', 'raster', 'raster-dem', atau 'video'.",
9, 4, "Tipe layer MapLibre manakah yang paling pas digunakan untuk merender data spasial bertipe geometri Area (Polygon) agar terisi warna solid?", ARRAY["circle", "line", "fill", "symbol"], 2, "", "Tipe layer `fill` merender poligon tertutup dengan opsi pewarnaan solid, transparansi, pola arsiran (pattern), serta garis tepi.",
9, 5, "Tipe layer MapLibre manakah yang digunakan jika kita ingin menggambar objek jalan raya (LineString) agar terlihat sebagai garis kontinu?", ARRAY["fill", "line", "circle", "heatmap"], 1, "", "Tipe layer `line` ditujukan khusus untuk menggambar garis atau outline poligon dengan pengaturan ketebalan, warna, dan jenis putus-putus (dasharray).",
9, 6, "Manakah format data masukan paling valid untuk properti `data` di dalam konfigurasi source bertipe 'geojson'?", ARRAY["String path file CSV lokal.", "Objek GeoJSON utuh (JavaScript Object) atau URL string yang mengarah ke file JSON/GeoJSON eksternal.", "Kumpulan biner data Shapefile zip.", "Array koordinat mentah tanpa informasi geometri."], 1, "", "Properti `data` di source 'geojson' dapat menerima objek JavaScript bertipe GeoJSON secara langsung atau string URL endpoint API yang mengembalikan format GeoJSON.",
9, 7, "Di dalam objek konfigurasi layer, properti manakah yang digunakan untuk mengikat layer tersebut ke ID sumber data yang sesuai?", ARRAY["id", "source", "source-layer", "data-source"], 1, "", "Properti `source` diisi string ID dari Source yang sudah didaftarkan sebelumnya melalui `map.addSource()`.",
9, 8, "Bagian properti layer manakah yang digunakan untuk menulis gaya visual seperti ukuran lingkaran (`circle-radius`) atau warna lingkaran (`circle-color`)?", ARRAY["layout", "paint", "properties", "styles"], 1, "", "Properti `paint` menangani visualisasi estetika detail tingkat pixel seperti warna, ketebalan, keburaman, bayangan yang dirender kartu grafis.",
9, 9, "Grup properti layer manakah yang digunakan untuk mengatur visibilitas layer (`visibility`) atau letak teks penanda (`text-anchor`)?", ARRAY["paint", "layout", "configuration", "attributes"], 1, "", "Properti `layout` mendefinisikan bagaimana browser memposisikan dan merencanakan objek spasial sebelum kartu grafis menggambarnya (paint).",
10, 0, "Fungsi bawaan MapLibre GL JS manakah yang dipanggil untuk memunculkan kotak popup informasi dinamis di atas peta?", ARRAY["map.showPopup()", "new maplibregl.Popup()", "new maplibregl.InfoWindow()", "map.addPopup()"], 1, "", "Konstruktor `new maplibregl.Popup(options)` menginstansiasi objek popup yang nantinya dapat dipasang ke koordinat tertentu di atas peta.",
10, 1, "Method popup manakah yang digunakan untuk menentukan posisi koordinat `[Bujur, Lintang]` berdirinya balon popup tersebut?", ARRAY["setLngLat()", "setHTML()", "addTo()", "setPosition()"], 0, "", "`setLngLat([longitude, latitude])` memposisikan letak popup secara spasial pada koordinat geografis bumi.",
10, 2, "Method popup manakah yang diisi dengan tag HTML untuk menyajikan tabel atribut data dinamis di dalam balon popup?", ARRAY["setText()", "setHTML()", "setContent()", "renderHTML()"], 1, "", "`setHTML(stringHTML)` menyuntikkan susunan elemen HTML (seperti tabel atau gambar) ke dalam popup untuk menyajikan informasi kaya estetika.",
10, 3, "Method popup manakah yang dipanggil paling akhir agar popup tersebut menempel secara fisik ke kanvas peta target?", ARRAY["append()", "addTo(map)", "setMap(map)", "render()"], 1, "", "`addTo(map)` menempelkan popup ke instans peta aktif untuk segera digambar di koordinat yang sesuai.",
10, 4, "Bagaimana cara mengubah ikon kursor mouse menjadi telunjuk (pointer) ketika mouse melayang di atas titik layer peta agar pengguna tahu titik tersebut bisa diklik?", ARRAY["map.setCursor('pointer');", "map.getCanvas().style.cursor = 'pointer';", "map.style.cursor = 'pointer';", "document.style.cursor = 'pointer';"], 1, "", "Mengubah properti kursor CSS pada elemen kanvas peta (`map.getCanvas().style.cursor = 'pointer'`) adalah trik standar UX WebGIS.",
10, 5, "Method penting MapLibre manakah yang digunakan untuk mengambil array fitur data spasial (geometri & atribut) yang berada tepat di bawah posisi kursor mouse saat diklik?", ARRAY["map.getFeatures()", "map.queryRenderedFeatures()", "map.selectFeatures()", "map.getFeaturesAtPoint()"], 1, "", "`map.queryRenderedFeatures(point, options)` melakukan query spasial sisi client yang sangat cepat, mengembalikan semua objek spasial di koordinat pixel tersebut.",
10, 6, "Bagaimana cara mendengarkan event klik user yang terjadi khusus pada sebuah layer bernama 'kantor-mapid'?", ARRAY["map.onClick('kantor-mapid', (e) => { ... });", "map.on('click', 'kantor-mapid', (e) => { ... });", "document.getElementById('kantor-mapid').addEventListener('click', ...);", "map.layer('kantor-mapid').on('click', ...);"], 1, "", "Sintaks `map.on('click', 'layer-id', callback)` mendaftarkan pendengar klik spasial yang disaring khusus untuk layer tersebut.",
10, 7, "Di dalam callback event klik peta, di manakah kita bisa membaca titik koordinat geografis lokasi klik tersebut secara presisi?", ARRAY["e.coordinates", "e.lngLat", "e.point", "e.pixel"], 1, "", "Objek argumen event `e` menyimpan properti `e.lngLat` (berisi Bujur Lintang spasial) dan `e.point` (posisi piksel X Y layar).",
10, 8, "Bagaimana cara menambahkan kontrol navigasi standar (tombol Zoom In, Zoom Out, dan Rotasi Kompas) ke pojok peta?", ARRAY["map.addZoomButtons()", "map.addControl(new maplibregl.NavigationControl())", "map.addComponent(new maplibregl.Zoom())", "new maplibregl.Controls().addTo(map)"], 1, "", "`map.addControl(new maplibregl.NavigationControl(), position)` memasang modul kontrol navigasi resmi bawaan MapLibre.",
10, 9, "Properti kustomisasi popup manakah yang wajib disetel agar balon popup menutup otomatis saat pengguna mengklik area kosong lain di peta?", ARRAY["closeOnClick: true", "closeOnBlur: true", "autoClose: true", "clickToDismiss: true"], 0, "", "Opsi `closeOnClick: true` adalah pengaturan standar UX untuk menjaga kenyamanan layar dari tumpukan popup yang tidak dibutuhkan.",
11, 0, "Apa tujuan utama dari visualisasi peta Heatmap?", ARRAY["Menampilkan rute perjalanan tercepat antar kota.", "Merepresentasikan konsentrasi intensitas atau densitas spasial dari kumpulan data titik menggunakan gradasi warna gradien hangat-dingin.", "Mengukur batas elevasi ketinggian tanah secara topografis.", "Menampilkan batas wilayah negara secara administratif."], 1, "", "Heatmap mengubah ribuan data titik rapat menjadi visual permukaan warna kontinu yang melambangkan tingkat kepadatan spasial objek di lapangan.",
11, 1, "Di dalam MapLibre GL JS, tipe layer (layer type) manakah yang digunakan untuk memvisualisasikan heatmap?", ARRAY["density", "heatmap", "blur-point", "gradient"], 1, "", "Tipe layer `heatmap` merender densitas spasial secara real-time memanfaatkan shader WebGL yang efisien di sisi browser client.",
11, 2, "Properti paint layer heatmap manakah yang digunakan untuk mengontrol seberapa luas area pengaruh penyebaran (radius keburaman) dari setiap titik data?", ARRAY["heatmap-weight", "heatmap-radius", "heatmap-intensity", "heatmap-spread"], 1, "", "`heatmap-radius` menentukan radius pencarian pengaruh spasial dalam satuan piksel. Semakin besar radius, semakin halus dan lebar gradien warna yang terbentuk.",
11, 3, "Properti paint layer heatmap manakah yang bertugas mengatur tingkat kontribusi signifikansi (bobot kepentingan) dari masing-masing titik berdasarkan kolom atribut angka tertentu?", ARRAY["heatmap-radius", "heatmap-weight", "heatmap-intensity", "heatmap-color"], 1, "", "`heatmap-weight` dapat diikat pada kolom atribut numerik (misal jumlah transaksi/penjualan) agar titik ber-nilai besar memancarkan panas yang lebih membara.",
11, 4, "Bagaimana cara kerja properti `heatmap-color` dalam mendefinisikan gradien warna?", ARRAY["Menerima satu string warna solid tunggal.", "Menerima ekspresi interpolasi skala 0.0 (densitas nol/transparan) hingga 1.0 (densitas maksimal/panas merah) untuk menetapkan peta gradasi warna gradien.", "Mengubah warna teks legenda peta.", "Menentukan warna outline tepi lingkaran titik."], 1, "", "`heatmap-color` menggunakan sintaks interpolasi RAMPA warna (biasanya menggunakan `['interpolate', ['linear'], ['heatmap-density'], 0, 'rgba(...)', 1, 'rgb(...)']`) untuk membangun spektrum gradien warna.",
11, 5, "Mengapa visualisasi heatmap harus disetel agar memudar (transparan penuh) ketika level zoom peta diperbesar sangat dekat dengan tanah?", ARRAY["Karena browser akan mengalami crash jika heatmap di-zoom terlalu dekat.", "Agar ketika kamera sudah sangat dekat, visual heatmap tidak lagi menutupi detail jalan raya/basemap, dan otomatis digantikan oleh visualisasi titik lokasi individu asli yang lebih presisi.", "Karena MapLibre tidak mampu merender warna di level zoom tinggi.", "Karena koordinat spasial akan otomatis meleset jika dipaksakan."], 1, "", "Ini adalah taktik UX kartografi: gunakan `heatmap-opacity` bertransisi memudar pada zoom tinggi, berbarengan dengan munculnya (fade-in) layer bertipe `circle`.",
11, 6, "Properti paint layer heatmap manakah yang bertugas sebagai pengali global untuk melipatgandakan kecerahan warna heatmap di seluruh wilayah peta?", ARRAY["heatmap-weight", "heatmap-intensity", "heatmap-radius", "heatmap-opacity"], 1, "", "`heatmap-intensity` bertindak sebagai penguat/multiplier sinyal panas global secara dinamis berdasarkan level perbesaran zoom peta.",
11, 7, "Gaya visualisasi spasial manakah yang paling pas bersinergi dipadukan bersama heatmap?", ARRAY["Peta kontur tanah bergunung.", "Legenda warna interaktif yang menjelaskan rentang arti dari spektrum warna dingin (kepadatan rendah) hingga hangat (kepadatan tinggi).", "Model 3D animasi perputaran awan.", "Grafik garis fluktuasi nilai saham bulanan."], 1, "", "Tanpa legenda spektrum warna, pembaca peta tidak bisa memahami arti dari gradasi warna heatmap tersebut secara kuantitatif.",
11, 8, "Apakah heatmap cocok digunakan untuk memvisualisasikan data rute jalan raya (LineString) secara kartografis?", ARRAY["Sangat cocok, rute jalan memang seharusnya divisualisasikan dengan warna gradien panas.", "Tidak cocok, heatmap dirancang khusus untuk memvisualisasikan akumulasi densitas dari sebaran data bertipe koordinat Titik (Point).", "Cocok, asalkan garis jalan raya diubah warnanya menjadi merah solid terlebih dahulu.", "Bisa, asalkan data jalan raya disimpan dalam format file Shapefile zip."], 1, "", "Heatmap didesain untuk menghitung kerapatan titik per satuan luas. Untuk data jalan, gunakan visualisasi multiline tergradasi atau layer bertipe `line`.",
11, 9, "Use-case industri manakah di bawah ini yang sangat pas dianalisis menggunakan visualisasi heatmap?", ARRAY["Memantau status online server database.", "Menganalisis wilayah rawan kriminalitas (crime hotspot) di perkotaan berdasarkan konsentrasi titik laporan polisi.", "Mengukur kecepatan akses loading halaman frontend.", "Menghitung rasio kompresi data spasial GeoJSON."], 1, "", "Pemetaan sebaran kriminalitas, kecelakaan lalu lintas, atau persebaran pelanggan ritel adalah use-case klasik hotspot analysis menggunakan heatmap.",
12, 0, "Apa tujuan utama dilakukannya analisis spasial 'Buffer' (Radius)?", ARRAY["Mencari nilai koordinat paling tengah dari sebuah poligon spasial.", "Membangun zona area poligon baru di sekeliling fitur spasial (bisa titik, garis, atau poligon) berdasarkan jarak radius jangkauan tertentu yang telah ditentukan.", "Memperkecil ukuran memori penyimpanan file GeoJSON.", "Mengatur skema warna basemap menjadi gelap-terang."], 1, "", "Buffering menciptakan zona jangkauan spasial yang sangat berguna untuk mengukur dampak pengaruh lokasi, seperti area terdampak kebisingan kereta atau radius antar kurir.",
12, 1, "Library JavaScript asinkronus open-source manakah yang sangat terkenal di industri untuk melakukan kalkulasi analisis spasial canggih (seperti buffering) langsung di sisi browser client?", ARRAY["Lodash", "Turf.js", "React.js", "Chart.js"], 1, "", "Turf.js menyediakan ratusan fungsi manipulasi spasial GIS berstandar industri yang ditulis murni dalam JavaScript untuk dieksekusi cepat di client.",
12, 2, "Method bawaan Turf.js manakah yang dipanggil untuk menghasilkan geometri poligon zona jangkauan radius di sekitar titik?", ARRAY["turf.circle() / turf.buffer()", "turf.distance()", "turf.area()", "turf.intersect()"], 0, "", "`turf.buffer(point, distance, options)` atau `turf.circle(center, radius, options)` menghasilkan poligon lingkaran spasial yang akurat di atas ellipsoid bumi.",
12, 3, "Bagaimana cara kita menampilkan poligon radius yang dihasilkan oleh Turf.js ke atas peta MapLibre?", ARRAY["Dengan mengekspornya ke format file .shp lokal di harddisk.", "Dengan memperbarui data di Source peta menggunakan method `map.getSource('id').setData(geojsonRadius)`.", "Dengan menulis ulang sintaks stylesheet globals.css.", "Dengan memanggil kembali perintah inisialisasi `new maplibregl.Map()`."], 1, "", "`setData(newData)` memperbarui isi data di source GeoJSON secara instan tanpa merusak state peta yang sedang berjalan, memicu render ulang geometri poligon baru.",
12, 4, "Di dalam method `turf.buffer()`, opsi properti manakah yang digunakan untuk menentukan unit satuan jarak (seperti 'kilometers', 'meters', atau 'miles')?", ARRAY["unit", "units", "measure", "scale"], 1, "", "Properti `units` menerima nilai string standar (misal `units: 'kilometers'` atau `units: 'meters'`) untuk memvalidasi presisi jarak radius spasial.",
12, 5, "Mengapa disarankan mengatur tingkat transparansi (`fill-opacity`) yang cukup tipis pada layer poligon radius di atas peta?", ARRAY["Karena warna tebal akan membebani RAM komputer pengguna.", "Agar poligon radius tidak menutupi visualisasi basemap jalan atau titik-titik penting (POIs) di bawahnya, menjaga keterbacaan peta yang baik.", "Karena MapLibre tidak mendukung poligon dengan warna pekat 100%.", "Agar poligon radius otomatis ter-update lebih cepat."], 1, "", "Menjaga opacity poligon di angka 0.15 s.d. 0.3 menjamin user tetap dapat melihat jalan, nama gedung, dan POI penting di balik cakupan radius jangkauan.",
12, 6, "Method Turf.js manakah yang digunakan untuk menghitung jarak lurus geografis antara dua titik koordinat spasial di bumi?", ARRAY["turf.distance()", "turf.buffer()", "turf.midpoint()", "turf.length()"], 0, "", "`turf.distance(point1, point2, options)` menghitung jarak garis lengkung terpendek di permukaan bola bumi (great-circle distance).",
12, 7, "Konsep GIS manakah yang memotong sekumpulan data titik berdasarkan batas poligon radius yang aktif (misal menyaring minimarket yang masuk di radius 1 km)?", ARRAY["Spatial Buffering", "Spatial Join / Point-in-Polygon (turf.booleanPointInPolygon)", "Coordinate Projection", "BBOX Clipping"], 1, "", "Pemeriksaan Point-in-Polygon (`turf.booleanPointInPolygon`) menyaring titik-titik spasial mana saja yang secara geometris berada di dalam perimeter poligon radius jangkauan.",
12, 8, "Use-case komersial manakah di bawah ini yang memanfaatkan analisis radius?", ARRAY["Mengukur total durasi pemutaran musik di website.", "Menampilkan wilayah jangkauan pesan-antar restoran (misal radius pengiriman 5 kilometer dari outlet) untuk memvalidasi pesanan pelanggan.", "Menghitung jumlah kata pada artikel di halaman web.", "Mendeteksi tipe sistem operasi yang dipakai pengguna."], 1, "", "Bisnis kuliner dan e-commerce lokal memanfaatkan radius jangkauan spasial untuk menentukan jangkauan operasional pengiriman logistik secara efisien.",
12, 9, "Apa keuntungan utama melakukan pemrosesan analisis spasial (seperti radius Turf.js) di browser client (client-side) dibandingkan mengirimkannya ke server backend (server-side)?", ARRAY["Hasil analisis dijamin 100% bebas dari risiko bug program.", "Interaktivitas instan tanpa jeda tunggu pengiriman data lewat internet (zero network latency), menghemat beban kerja komputasi server utama.", "Client-side otomatis mengamankan data dari serangan hacker global.", "Tidak perlu menulis kode program JavaScript."], 1, "", "Dengan menghitung di browser pengguna via Turf.js, peta merespon geseran kursor radius secara real-time tanpa perlu bolak-balik mengirim request ke database server.",
13, 0, "Apa definisi yang paling tepat mengenai 'Isochrone' dalam analisis transportasi spasial?", ARRAY["Garis atau poligon di atas peta yang menghubungkan titik-titik dengan waktu tempuh perjalanan yang sama menuju satu lokasi pusat, menggunakan moda transportasi tertentu.", "Alat pengukur tingkat kemiringan permukaan lereng bukit spasial.", "Metode kompresi database spasial berkecepatan tinggi.", "Tingkat transparansi warna pada peta satelit."], 0, "", "Isochrone berasal dari kata Yunani 'isos' (sama) dan 'chronos' (waktu). Poligon Isochrone memetakan jangkauan area tempuh nyata berbasis jaringan jalan raya.",
13, 1, "Apa perbedaan krusial antara analisis radius lingkaran biasa (Buffer) dengan analisis Isochrone?", ARRAY["Radius buffer dihitung menggunakan satuan waktu, sedangkan Isochrone menggunakan satuan kilometer.", "Radius buffer dihitung berdasarkan jarak lurus udara ('as the crow flies') mengabaikan rintangan; sedangkan Isochrone dihitung berdasarkan jaringan jalan riil, kecepatan kendaraan, hambatan lalu lintas, dan arah jalan satu arah.", "Buffer selalu menghasilkan bentuk poligon yang tidak beraturan sedangkan Isochrone selalu lingkaran sempurna.", "Isochrone hanya bisa dihitung menggunakan data spasial berformat Shapefile."], 1, "", "Radius udara mengabaikan hambatan fisik (sungai, gedung, dsb). Isochrone menyajikan jangkauan berkendara yang jauh lebih realistis karena mematuhi aturan jaringan jalan nyata.",
13, 2, "Bagaimana sebuah aplikasi WebGIS frontend mendapatkan poligon Isochrone secara dinamis?", ARRAY["Dengan menghitung rumus matematika jalan menggunakan loop JavaScript di client-side.", "Melakukan request asinkronus (fetch API) ke API Isochrone eksternal (seperti MAPID Isochrone API, OpenRouteService, atau Mapbox API) dengan mengirim titik pusat dan parameter waktu tempuh.", "Menggambar poligon secara manual menggunakan digitize tool di layar.", "Membaca file citra satelit raster yang tersimpan di server lokal."], 1, "", "Perhitungan rute jaringan jalan sangat kompleks dan membutuhkan database jaringan jalan global. Frontend cukup mengirim koordinat pusat dan menerima poligon GeoJSON hasil kalkulasi server API.",
13, 3, "Di dalam pemanggilan API Isochrone, parameter input apa saja yang umumnya wajib kita kirimkan?", ARRAY["Username database dan password admin.", "Koordinat titik pusat (`[bujur, lintang]`), waktu batas tempuh (misal '15 menit'), dan moda transportasi (jalan kaki, motor, mobil).", "Lebar resolusi monitor layar client dan versi sistem operasi.", "Nama basemap yang sedang diaktifkan di MapLibre."], 1, "", "Parameter utama ini dibutuhkan mesin kalkulasi routing untuk menelusuri segmen jaringan jalan yang relevan dan menghitung batas akumulasi waktu tempuh.",
13, 4, "Format data spasial apakah yang dikembalikan oleh API Isochrone untuk kemudian dirender sebagai layer poligon di MapLibre?", ARRAY["GeoJSON berjenis Polygon / MultiPolygon", "Citra gambar raster PNG transparan", "File biner DXF AutoCAD", "Kumpulan teks koordinat mentah CSV"], 0, "", "Respons berformat GeoJSON dengan geometri Polygon atau MultiPolygon sangat mudah di-parse dan langsung dimasukkan ke source peta MapLibre.",
13, 5, "Use-case perencanaan tata kota (smart city) manakah yang paling ideal memanfatkan analisis Isochrone?", ARRAY["Menghitung rasio pajak daerah tahunan.", "Menganalisis jangkauan layanan fasilitas kesehatan darurat (akses rumah sakit dalam batas waktu tanggap darurat berkendara 10 dan 15 menit).", "Membuat sistem absensi kehadiran online pegawai kelurahan.", "Mempercepat proses load data peta dasar."], 1, "", "Analisis isochrone membantu tata kota menilai aksesibilitas fasilitas umum vital agar merata dijangkau masyarakat dalam rentang waktu yang aman.",
13, 6, "Bagaimana cara menampilkan visualisasi bertumpuk dari area jangkauan isochrone waktu yang berbeda (misal 5 menit hijau, 10 menit kuning, 15 menit merah)?", ARRAY["Dengan membuat 3 halaman website yang terpisah.", "Dengan merender poligon-poligon waktu tersebut secara bertumpuk di peta, memastikan poligon waktu terbesar (15 menit) diletakkan di paling bawah agar tidak menutupi poligon kecil.", "Dengan memadukan warna poligon menjadi hitam pekat.", "Dengan mengunduh file video animasi perjalanan kurir."], 1, "", "Poligon jangkauan yang lebih kecil (waktu tempuh singkat) harus ditumpuk di atas poligon besar agar tidak tersembunyi/tertutupi (occlusion).",
13, 7, "Moda transportasi manakah yang biasanya menghasilkan poligon Isochrone paling luas pada batas waktu tempuh yang sama (misal sama-sama 15 menit)?", ARRAY["Jalan Kaki (Walking)", "Sepeda (Cycling)", "Sepeda Motor / Mobil (Driving)", "Semuanya menghasilkan luas poligon yang identik"], 2, "", "Kecepatan berkendara mobil/motor di jalan raya jauh lebih tinggi dibanding jalan kaki, sehingga mampu menempuh segmen jalan yang lebih jauh dalam rentang waktu yang sama.",
13, 8, "Hambatan fisik di lapangan manakah yang otomatis dihitung oleh algoritma routing Isochrone saat membatasi area jangkauan?", ARRAY["Suhu udara rata-rata perkotaan.", "Jaringan jalan searah (one-way streets), kemacetan lalu lintas, jembatan penyeberangan sungai, dan pembatas jalan toll.", "Warna marka jalan raya.", "Merek kendaraan yang dikendarai oleh pengguna."], 1, "", "Algoritma pencarian jalur terpendek (seperti Dijkstra atau A*) pada grafik jalan raya memperhitungkan batasan bobot (weight) hukum lalu lintas fisik jalan.",
13, 9, "Mengapa visualisasi Isochrone sangat bernilai tinggi dalam studi penentuan lokasi gerai ritel komersial baru?", ARRAY["Karena visualisasi Isochrone otomatis mendatangkan investasi modal gratis.", "Karena menyajikan pemetaan jangkauan konsumen riil yang logis berdasarkan kemudahan waktu perjalanan mereka menuju toko, bukan sekadar jarak burung linear.", "Karena Isochrone mempercepat rendering visual peta hingga 10 kali lipat.", "Karena data isochrone dijamin tidak pernah berubah selamanya."], 1, "", "Konsumen berbelanja berdasarkan kemudahan akses waktu tempuh berkendara riil. Analisis isochrone memetakan 'Catchment Area' (area tangkapan pasar) bisnis secara akurat.",
14, 0, "Apa tujuan utama dari proses 'Refinement' dalam pengembangan WebGIS?", ARRAY["Mengganti seluruh library JavaScript menjadi bahasa Python spasial.", "Mengoptimalkan kode sumber, membersihkan asset, mempercepat waktu memuat (loading), menyempurnakan interaktivitas UX, dan memastikan kesiapan deployment produk.", "Menghapus seluruh fitur peta agar website menjadi lebih ringan.", "Membuat dokumentasi petunjuk penggunaan dalam format cetak tebal."], 1, "", "Refinement merapikan sisi arsitektur kode, merampingkan file, menangani edge-cases, dan memoles elemen visual agar layak dipamerkan sebagai portofolio profesional.",
14, 1, "Mengapa kita disarankan menampilkan komponen 'Loading Skeleton' atau 'Progress Spinner' saat peta sedang diinisialisasi?", ARRAY["Untuk mempercepat koneksi internet client secara otomatis.", "Memberikan umpan balik visual (feedback) yang baik bagi pengguna agar mereka tahu bahwa aplikasi sedang memproses pemuatan peta/data spasial, mencegah kebingungan layar kosong.", "Karena MapLibre mewajibkan keberadaan spinner agar peta bisa merender.", "Untuk menyembunyikan log error JavaScript di console."], 1, "", "UX loading state yang baik mencegah pengguna mengira aplikasi web rusak/hang saat sedang mengunduh ubin peta dasar atau data spasial berukuran besar.",
14, 2, "Manakah tindakan optimasi performa WebGIS yang paling tepat untuk menangani file GeoJSON yang berukuran terlalu besar (misal > 50 Megabytes)?", ARRAY["Mengompres data dengan mengubah ekstensi file menjadi .zip lalu dipanggil langsung oleh fetch API.", "Melakukan penyederhanaan geometri poligon (simplification via QGIS/Mapshaper), menyaring atribut yang tidak perlu, atau mengonversi data menjadi format Vector Tiles spasial.", "Menghapus setengah koordinat titik secara acak menggunakan Notepad.", "Menurunkan tingkat resolusi warna monitor laptop client."], 1, "", "GeoJSON besar membebani bandwidth dan RAM browser client. Teknik simplifikasi menyederhanakan titik geometri tanpa merusak bentuk dasar kartografinya secara signifikan.",
14, 3, "Mengapa kredensial rahasia (seperti Database Password) tidak boleh ditulis langsung (hardcoded) secara terang-terangan di file JavaScript frontend?", ARRAY["Karena browser akan otomatis memblokir file JavaScript tersebut.", "Karena kode JavaScript frontend dikirimkan utuh ke browser client, sehingga siapa saja dapat mengintip kredensial tersebut dengan mudah melalui fitur View Source / Developer Tools, memicu ancaman kebocoran database spasial privat.", "Karena kredensial rahasia memicu peningkatan beban komputasi CPU browser.", "Karena MapLibre tidak mendukung koneksi database terenkripsi."], 1, "", "Sisi client (frontend) tidak pernah aman untuk menyimpan rahasia. Operasi sensitif database wajib ditangani backend server yang dilindungi kredensial aman.",
14, 4, "Platform hosting modern open-source manakah yang sangat disukai developer untuk mendeploy website frontend HTML/CSS/JS statis secara gratis, cepat, dan otomatis terhubung ke repositori GitHub?", ARRAY["PostgreSQL cloud", "Netlify / GitHub Pages / Vercel", "QGIS Desktop Server", "Anaconda Python Suite"], 1, "", "Platform seperti Netlify, Vercel, dan GitHub Pages dirancang untuk menghosting aset frontend statis langsung dari repositori Git secara efisien dan aman.",
14, 5, "Dalam pengembangan web modern, apa fungsi dari file `.env`?", ARRAY["Menyimpan baris kode logika animasi css.", "Menyimpan variabel lingkungan (environment variables) seperti API key atau URL server backend secara terpisah dari kode sumber utama, memudahkan manajemen konfigurasi antar environment (dev, production).", "Mengatur ukuran resolusi visual peta dasar.", "Mengompres ukuran gambar basemap."], 1, "", "File `.env` menampung parameter konfigurasi dinamis. Di platform hosting, kita dapat mengatur variabel lingkungan ini pada dashboard deployment tanpa membeberkannya di repositori publik.",
14, 6, "Command npm manakah yang dijalankan untuk memvalidasi kualitas kode dan menangkap kesalahan sintaksis/struktur error di proyek Next.js sebelum build?", ARRAY["npm run dev", "npm run lint", "npm run start", "npm run clean"], 1, "", "`npm run lint` memicu ESLint untuk memindai file kode, mendeteksi variabel yang tidak terpakai, sintaks rusak, atau pelanggaran best-practice standar coding.",
14, 7, "Command npm manakah yang dijalankan untuk mengompilasi dan membangun aplikasi Next.js menjadi paket bundel produksi (production bundle) siap saji yang optimal?", ARRAY["npm run build", "npm run dev", "npm run watch", "npm run debug"], 0, "", "`npm run build` melakukan optimasi kompilasi, minifikasi JS/CSS, optimasi gambar, dan menghasilkan halaman statis (SSG/ISR) yang super cepat.",
14, 8, "Apa kriteria minimum yang wajib dipenuhi agar proyek WebGIS dinilai siap dipublikasikan (portfolio-ready)?", ARRAY["Aplikasi harus memiliki minimal 10 halaman menu yang sangat panjang.", "Memiliki visual antarmuka (UI/UX) yang bersih rapi, peta interaktif lancar dimuat, fungsionalitas spasial berjalan tanpa bug error di console, serta dideploy secara publik dengan link akses aktif.", "Menggunakan database PostgreSQL lokal yang tidak terhubung ke hosting cloud.", "Kode sumber disembunyikan seluruhnya dari publik secara total."], 1, "", "Portfolio yang menarik bagi industri adalah portfolio yang memiliki problem-solving context yang jelas, fungsional, dan dapat diakses langsung oleh rekruter secara online.",
14, 9, "Mengapa penting bagi seorang praktisi WebGIS untuk menulis dokumentasi ringkas (README) pada repositori GitHub proyek mereka?", ARRAY["README wajib diisi agar file JavaScript bisa terbaca oleh web server.", "Membantu orang lain (dan calon rekruter) memahami dengan cepat: tujuan aplikasi WebGIS dibuat, masalah apa yang diselesaikan, cara kerja arsitektur sistem, teknologi tools yang digunakan, serta panduan instalasi lokal.", "README digunakan untuk menyimpan API key rahasia agar aman.", "Untuk meningkatkan nilai peringkat di papan skor kuis secara otomatis."], 1, "", "Dokumentasi README.md yang terstruktur dengan baik mencerminkan profesionalisme engineering, mempermudah kolaborasi tim, dan meningkatkan nilai jual portofolio karir.",
15, 0, "Apa peran utama bahasa pemrograman Python di industri pengolahan data spasial (GIS)?", ARRAY["Merender antarmuka peta interaktif di dalam browser client secara real-time.", "Mengolah, menganalisis, membersihkan data spasial skala besar, serta melakukan preprocessing data spasial secara otomatis di sisi backend / data engineering.", "Menggantikan fungsi HTML/CSS dalam merancang tombol website.", "Meningkatkan kecepatan jaringan internet server hosting."], 1, "", "Python memiliki ekosistem library geospasial yang sangat perkasa untuk mengotomatisasi pemrosesan data, kalkulasi statistik spasial berat, dan data warehousing.",
15, 1, "Library Python manakah yang bertindak sebagai standar utama industri untuk membaca, menulis, dan memanipulasi data spasial vektor (seperti tabel koordinat) layaknya Pandas?", ARRAY["Matplotlib", "GeoPandas", "Shapely", "Fiona"], 1, "", "GeoPandas memperluas kemampuan Pandas dengan menambahkan kolom khusus `geometry` untuk menampung objek spasial dan mendukung operasi GIS secara tabular.",
15, 2, "Library Python manakah yang bertugas menangani kalkulasi matematika geometri spasial dasar (seperti menghitung centroid, irisan poligon, atau jarak) secara internal di belakang GeoPandas?", ARRAY["NumPy", "Shapely", "PyProj", "Rasterio"], 1, "", "Shapely fokus pada manipulasi dan analisis geometri spasial planar, melakukan operasi topologis berstandar OGC.",
15, 3, "Dalam Python, representasi tipe data spasial vektor tabel lengkap dengan kolom geometrinya ditampung di dalam objek...", ARRAY["DataFrame", "GeoDataFrame", "GeoSeries", "SpatialArray"], 1, "", "GeoDataFrame adalah struktur data tabular utama di GeoPandas yang wajib memiliki minimal satu kolom geometri spasial aktif.",
15, 4, "Method GeoPandas manakah yang dipanggil untuk memuat (membaca) file spasial eksternal (misal .geojson atau Shapefile) langsung menjadi sebuah GeoDataFrame?", ARRAY["gpd.read_file()", "gpd.load_spatial()", "gpd.read_geojson()", "gpd.open()"], 0, "", "`gpd.read_file('path_ke_file')` otomatis mengenali format file spasial biner maupun teks berkat dukungan engine fiona di belakangnya.",
15, 5, "Properti atau kolom khusus wajib manakah yang melambangkan koordinat objek spasial di dalam sebuah GeoDataFrame?", ARRAY["coordinates", "geometry", "shape", "geom_type"], 1, "", "Kolom `geometry` menampung objek-objek geometri spasial (Point, LineString, Polygon) yang diproses menggunakan engine Shapely.",
15, 6, "Bagaimana cara mengekspor (menyimpan) kembali data spasial yang telah diolah di GeoPandas menjadi file GeoJSON agar siap digunakan di WebGIS frontend kita?", ARRAY["gdf.save_file('output.geojson', format='json')", "gdf.to_file('output.geojson', driver='GeoJSON')", "gdf.write_geojson('output.geojson')", "gdf.export('output.geojson')"], 1, "", "Method `to_file()` memfasilitasi penulisan GeoDataFrame kembali ke file fisik disk, di mana penentuan `driver='GeoJSON'` menjamin keluaran berformat teks GeoJSON standar.",
15, 7, "Library Python manakah yang bertindak khusus menangani proses proyeksi koordinat dan transformasi EPSG secara presisi?", ARRAY["PyProj", "Shapely", "Fiona", "Geopy"], 0, "", "PyProj adalah interface Python untuk pustaka komputasi proyeksi kartografi PROJ, sangat krusial dalam mengonversi koordinat antar EPSG.",
15, 8, "Use-case integrasi Python spasial dan WebGIS yang paling efisien di industri adalah...", ARRAY["Merancang tata letak CSS grid dashboard.", "Membuat script ETL (Extract-Transform-Load) otomatis yang mengunduh data satelit berkala, melakukan komputasi analisis spasial rumit dengan Python, lalu mengirimkan hasilnya ke API GEO MAPID secara terjadwal untuk segera ditampilkan di peta WebGIS client.", "Mendeteksi masukan email pengguna di form login.", "Mengurangi tingkat resolusi visual peta dasar."], 1, "", "Python unggul dalam pemrosesan data backend / pipeline otomatis. Python mengolah 'big data' spasial yang rumit di balik layar, lalu menyuplai data siap saji yang ringan ke WebGIS frontend.",
15, 9, "Method GeoDataFrame manakah yang digunakan untuk memproyeksikan ulang (transformasi CRS) sistem koordinat data spasial (misal dari EPSG:4326 derajat menjadi EPSG:3857 meter)?", ARRAY["gdf.set_crs()", "gdf.to_crs()", "gdf.project()", "gdf.reproject()"], 1, "", "`to_crs(epsg=3857)` menghitung ulang seluruh titik geometri spasial di GeoDataFrame ke sistem referensi koordinat target terproyeksi secara matematis.";
